package requests;

import io.gatling.javaapi.core.ChainBuilder;

import static io.gatling.javaapi.core.CoreDsl.*;
import static io.gatling.javaapi.http.HttpDsl.*;

/**
 * User authentication and account-related API requests.
 * Includes login, signup, account management flows.
 */
public class AuthRequests {

    /**
     * POST /userAccount/login - Login user
     */
    public static ChainBuilder loginUser() {
        return exec(http("POST User Login")
                .post("/userAccount/login")
                .body(StringBody("{\"email\":\"#{email}\",\"password\":\"#{password}\"}"))
                .asJson()
                .check(status().is(200))
                .check(jsonPath("$.responseCode").exists())
                .check(jsonPath("$.user").exists())
                .check(jsonPath("$.user.id").saveAs("userId"))
                .check(jsonPath("$.user.email").saveAs("userEmail")));
    }

    /**
     * POST /userAccount/signup - Create new user account
     */
    public static ChainBuilder signupUser() {
        return exec(http("POST User Signup")
                .post("/userAccount/signup")
                .body(Body.STRING("{\"name\":\"#{userName}\",\"email\":\"#{email}\",\"password\":\"#{password}\"}"))
                .asJson()
                .check(status().is(200))
                .check(jsonPath("$.responseCode").exists()));
    }

    /**
     * GET /userAccount/login/{email}/{password} - Login with GET (alternative endpoint)
     */
    public static ChainBuilder loginWithGet() {
        return exec(http("GET User Login")
                .get("/userAccount/login/#{email}/#{password}")
                .check(status().is(200))
                .check(jsonPath("$.user").exists())
                .check(jsonPath("$.user.id").saveAs("userId")));
    }

    /**
     * DELETE /userAccount/delete/{email}/{password} - Delete user account
     */
    public static ChainBuilder deleteUserAccount() {
        return exec(http("DELETE User Account")
                .delete("/userAccount/delete/#{email}/#{password}")
                .check(status().is(200))
                .check(jsonPath("$.responseCode").is(200)));
    }

    /**
     * GET /userAccount/{email} - Get user details
     */
    public static ChainBuilder getUserDetails() {
        return exec(http("GET User Details")
                .get("/userAccount/#{email}")
                .check(status().is(200))
                .check(jsonPath("$.user").exists()));
    }

    /**
     * Composite flow: Complete user journey (signup, login, get details)
     */
    public static ChainBuilder userAuthenticationFlow() {
        return signupUser()
                .pause(2)
                .exec(loginWithGet())
                .pause(1, 2)
                .exec(getUserDetails());
    }

}

