package requests;

import io.gatling.javaapi.core.ChainBuilder;

import static io.gatling.javaapi.core.CoreDsl.*;
import static io.gatling.javaapi.http.HttpDsl.*;

/**
 * Cart and checkout-related API requests.
 * Includes creating cart, adding/removing products, and completing orders.
 */
public class CartRequests {

    /**
     * POST /cartAdd - Add product to cart
     */
    public static ChainBuilder addProductToCart() {
        return exec(http("POST Add to Cart")
                .post("/cartAdd")
                .body(StringBody("{\"id\":\"#{productId}\"}"))
                .asJson()
                .check(status().is(200))
                .check(jsonPath("$.responseCode").exists()));
    }

    /**
     * DELETE /cartDelete/{id} - Remove product from cart
     */
    public static ChainBuilder removeProductFromCart() {
        return exec(http("DELETE Remove from Cart")
                .delete("/cartDelete/1")
                .check(status().is(200))
                .check(jsonPath("$.responseCode").exists()));
    }

    /**
     * GET /cartList - Get all products in cart
     */
    public static ChainBuilder getCartList() {
        return exec(http("GET Cart List")
                .get("/cartList")
                .check(status().is(200))
                .check(jsonPath("$.cart").exists()));
    }

    /**
     * DELETE /cartClear - Clear entire cart
     */
    public static ChainBuilder clearCart() {
        return exec(http("DELETE Clear Cart")
                .delete("/cartClear")
                .check(status().is(200))
                .check(jsonPath("$.responseCode").exists()));
    }

    /**
     * POST /createOrder - Create order from cart
     */
    public static ChainBuilder createOrder() {
        return exec(http("POST Create Order")
                .post("/createOrder")
                .body(Body.STRING("{\"user_id\":\"#{userId}\"}"))
                .asJson()
                .check(status().is(200))
                .check(jsonPath("$.responseCode").exists())
                .check(jsonPath("$.order_id").saveAs("orderId")));
    }

    /**
     * Composite flow: Browse and add products to cart
     */
    public static ChainBuilder shoppingFlow() {
        return exec(ProductRequests.getProducts())
                .pause(1, 2)
                .exec(addProductToCart())
                .pause(1)
                .exec(getCartList())
                .pause(1, 2)
                .exec(addProductToCart())
                .pause(1)
                .exec(getCartList());
    }

    /**
     * Composite flow: Complete checkout (add to cart, create order)
     */
    public static ChainBuilder checkoutFlow() {
        return shoppingFlow()
                .pause(2)
                .exec(createOrder())
                .pause(1)
                .exec(clearCart());
    }

}

