package requests;

import io.gatling.javaapi.core.ChainBuilder;
import io.gatling.javaapi.core.Body;

import static io.gatling.javaapi.core.CoreDsl.*;
import static io.gatling.javaapi.http.HttpDsl.*;

/**
 * Review and comment-related API requests.
 * Includes getting and creating product reviews.
 */
public class ReviewRequests {

    /**
     * GET /productReviews/{id} - Get reviews for a product
     */
    public static ChainBuilder getProductReviews() {
        return exec(http("GET Product Reviews")
                .get("/productReviews/1")
                .check(status().is(200))
                .check(jsonPath("$.reviews").exists()));
    }

    /**
     * POST /productReview - Submit a review for a product
     */
    public static ChainBuilder submitProductReview() {
        return exec(http("POST Submit Review")
                .post("/productReview")
                .body(Body.STRING("{\"id\":\"#{productId}\",\"email\":\"#{email}\",\"review_title\":\"#{reviewTitle}\",\"review_text\":\"#{reviewText}\",\"rating\":5}"))
                .asJson()
                .check(status().is(200))
                .check(jsonPath("$.responseCode").exists()));
    }

    /**
     * Composite flow: View and add reviews
     */
    public static ChainBuilder reviewFlow() {
        return getProductReviews()
                .pause(1)
                .exec(submitProductReview())
                .pause(1);
    }

}

